"use client";

import { createContext, useContext, useState, useEffect, useCallback, ReactNode } from "react";
import { AUTH_KEY } from "@/lib/constants";
import { validateApiKey } from "@/lib/torbox";
import { TorboxUser } from "@/types/torbox";

interface AuthContextType {
  apiKey: string | null;
  user: TorboxUser | null;
  loading: boolean;
  login: (key: string) => Promise<void>;
  logout: () => void;
}

const AuthContext = createContext<AuthContextType>({
  apiKey: null,
  user: null,
  loading: true,
  login: async () => {},
  logout: () => {},
});

export function AuthProvider({ children }: { children: ReactNode }) {
  const [apiKey, setApiKey] = useState<string | null>(null);
  const [user, setUser] = useState<TorboxUser | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const stored = localStorage.getItem(AUTH_KEY);
    if (stored) {
      validateApiKey(stored)
        .then((u) => {
          setApiKey(stored);
          setUser(u);
        })
        .catch(() => {
          localStorage.removeItem(AUTH_KEY);
        })
        .finally(() => setLoading(false));
    } else {
      setLoading(false);
    }
  }, []);

  const login = useCallback(async (key: string) => {
    const u = await validateApiKey(key);
    localStorage.setItem(AUTH_KEY, key);
    setApiKey(key);
    setUser(u);
  }, []);

  const logout = useCallback(() => {
    localStorage.removeItem(AUTH_KEY);
    setApiKey(null);
    setUser(null);
  }, []);

  return (
    <AuthContext.Provider value={{ apiKey, user, loading, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  return useContext(AuthContext);
}
